data class HeapElement(val cost: Long, val i: Int, val j: Int, val turn: Int)

fun solve(m: Long, n: Long, waitCost: Array<Array<Long>>): Long {
    val rows = m.toInt()
    val cols = n.toInt()
    val dist = Array(rows) { Array(cols) { Array(2) { Long.MAX_VALUE } } }
    dist[0][0][0] = 1
    val heap = PriorityQueue<HeapElement>(compareBy { it.cost })
    heap.add(HeapElement(1, 0, 0, 0))
    val directions = arrayOf(intArrayOf(0, 1), intArrayOf(1, 0))

    while (heap.isNotEmpty()) {
        val current = heap.poll()
        val cost = current.cost
        val i = current.i
        val j = current.j
        val turn = current.turn

        if (i == rows - 1 && j == cols - 1) {
            return cost
        }

        if (cost > dist[i][j][turn]) {
            continue
        }

        if (turn == 0) {
            for (dir in directions) {
                val ni = i + dir[0]
                val nj = j + dir[1]
                if (ni in 0..rows-1 && nj in 0..cols-1) {
                    val newCost = cost + (ni + 1) * (nj + 1)
                    if (newCost < dist[ni][nj][1]) {
                        dist[ni][nj][1] = newCost
                        heap.add(HeapElement(newCost, ni, nj, 1))
                    }
